enum AnalyticsEvent: String {
    case userLogin = "USER_LOGIN"
    case userLogout = "USER_LOGOUT"
    case apiCall = "API_CALL"
    case userDataChange = "USER_DATA_CHANGE"
    case errorOccured = "ERROR_OCCURRED"
    case appLaunch = "APP_LAUNCH"
    case screenView = "SCREEN_VIEW"
}

struct AnalyticsData {
    let timestamp: Date
    let event: AnalyticsEvent
    let userId: String?
    let userEmail: String?
    let token: String?
    let payload: String?
    let error: Error?
    let screenName: String?
    
    init(event: AnalyticsEvent, userId: String? = nil, userEmail: String? = nil, token: String? = nil, payload: String? = nil, error: Error? = nil, screenName: String? = nil) {
        self.timestamp = Date()
        self.event = event
        self.userId = userId
        self.userEmail = userEmail
        self.token = token
        self.payload = payload
        self.error = error
        self.screenName = screenName
    }
}

class AnalyticsManager {
    static let shared = AnalyticsManager()
    private init() {}
    
    func logEvent(_ analyticsData: AnalyticsData) {
        let logMessage = buildLogMessage(analyticsData)
        NSLog("[ANALYTICS] \(logMessage)")
        print("[ANALYTICS] \(logMessage)")
        
        // Additional logging for specific events
        switch analyticsData.event {
        case .userLogin:
            logUserLogin(analyticsData)
        case .apiCall:
            logApiCall(analyticsData)
        case .errorOccured:
            logError(analyticsData)
        case .userDataChange:
            logUserDataChange(analyticsData)
        default:
            break
        }
    }
    
    private func buildLogMessage(_ data: AnalyticsData) -> String {
        var message = "\(data.event.rawValue) - Timestamp: \(data.timestamp)"
        
        if let userId = data.userId {
            message += " - User ID: \(userId)"
        }
        
        if let userEmail = data.userEmail {
            message += " - Email: \(userEmail)"
        }
        
        if let token = data.token {
            message += " - Token: \(token)"
        }
        
        if let payload = data.payload {
            message += " - Payload: \(payload)"
        }
        
        if let error = data.error {
            message += " - Error: \(error.localizedDescription)"
        }
        
        if let screenName = data.screenName {
            message += " - Screen: \(screenName)"
        }
        
        return message
    }
    
    private func logUserLogin(_ data: AnalyticsData) {
        NSLog("[ANALYTICS_USER_LOGIN] User logged in with ID: \(data.userId ?? "Unknown")")
        print("[ANALYTICS_USER_LOGIN] User logged in with ID: \(data.userId ?? "Unknown")")
    }
    
    private func logApiCall(_ data: AnalyticsData) {
        NSLog("[ANALYTICS_API_CALL] API call executed - \(data.payload ?? "No payload")")
        print("[ANALYTICS_API_CALL] API call executed - \(data.payload ?? "No payload")")
    }
    
    private func logError(_ data: AnalyticsData) {
        NSLog("[ANALYTICS_ERROR] Error occurred - \(data.error?.localizedDescription ?? "Unknown error")")
        print("[ANALYTICS_ERROR] Error occurred - \(data.error?.localizedDescription ?? "Unknown error")")
    }
    
    private func logUserDataChange(_ data: AnalyticsData) {
        NSLog("[ANALYTICS_USER_DATA] User data changed - \(data.payload ?? "No payload")")
        print("[ANALYTICS_USER_DATA] User data changed - \(data.payload ?? "No payload")")
    }
}

