class DataManager {
    func updateUserData(userId: String, data: [String: Any]) {
        let changes = data.map { "\($0.key): \($0.value)" }.joined(separator: ", ")
        AnalyticsManager.shared.logUserDataChange(userId: userId, changes: changes)
    }
    
    func makeApiCall(url: String, method: String) {
        AnalyticsManager.shared.logEvent(AnalyticsData(event: .apiCall, payload: "Making \(method) call to \(url)"))
    }
